  (() => {
    const data = get_months.data;
    if (!data || data.length === 0) return "No data available";

    return data.map(row => {
      const cCount = Number(row.count);
      const sCount = data.length; 

      // Pluralization logic
      const cLabel = cCount === 1 ? "contract" : "contracts";

      /* IMPORTANT: Since your SQL query groups by month, 
         row.count is the total contracts for that month.
         To get the number of shipments per month from your NEW SQL, 
         the query would actually need to be COUNT(DISTINCT shipment_number).
      */

      return `<strong>${row.shipment_month}</strong>: ${cCount} ${cLabel}`;
    }).join('<br>');
  })()
}}
